// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title Voltx Vault
 * @dev Inheritance logic with heartbeat and grace periods.
 */
contract Vault {
    enum Status { Active, PendingRelease, Released }

    struct Beneficiary {
        address wallet;
        uint16 shareBps; // 10000 = 100%, 5000 = 50%
    }

    address public owner;
    uint256 public lastHeartbeat;
    uint256 public inactivityPeriod; // e.g., 30 days
    uint256 public gracePeriod;      // e.g., 7 days
    Status public status;

    Beneficiary[] public beneficiaries;

    event HeartbeatUpdated(uint256 timestamp);
    event ReleaseTriggered(uint256 graceEndTimestamp);
    event FundsDistributed(uint256 totalAmount);

    constructor(uint256 _inactivity, uint256 _grace) {
        owner = msg.sender;
        inactivityPeriod = _inactivity;
        gracePeriod = _grace;
        lastHeartbeat = block.timestamp;
        status = Status.Active;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this");
        _;
    }

    // Reset the timer - the "I'm Alive" button
    function heartbeat() external onlyOwner {
        lastHeartbeat = block.timestamp;
        status = Status.Active;
        emit HeartbeatUpdated(block.timestamp);
    }

    // Only a beneficiary can trigger this if the owner is inactive
    function triggerRelease() external {
        require(status == Status.Active, "Already triggered");
        require(block.timestamp > lastHeartbeat + inactivityPeriod, "Owner is still active");
        
        bool isBeneficiary = false;
        for (uint i = 0; i < beneficiaries.length; i++) {
            if (beneficiaries[i].wallet == msg.sender) {
                isBeneficiary = true;
                break;
            }
        }
        require(isBeneficiary, "Not an authorized beneficiary");

        status = Status.PendingRelease;
        emit ReleaseTriggered(block.timestamp + gracePeriod);
    }

    // Function to add beneficiaries - Owner only
    function setBeneficiaries(address[] memory _wallets, uint16[] memory _bps) external onlyOwner {
        require(_wallets.length == _bps.length, "Mismatched arrays");
        delete beneficiaries;
        uint16 totalBps = 0;
        for (uint i = 0; i < _wallets.length; i++) {
            totalBps += _bps[i];
            beneficiaries.push(Beneficiary(_wallets[i], _bps[i]));
        }
        require(totalBps == 10000, "Must equal 100%");
    }

    receive() external payable {} // Allow the vault to hold ETH
}

